/**
 * Tests for calculatePartnerPayout
 *
 * Covers AC1–AC5 from the revenue sharing spec.
 * Run with: npx tsx --test calculatePartnerPayout.test.ts
 *   or:     node --experimental-strip-types --test calculatePartnerPayout.test.ts  (Node 22+)
 */
import { strict as assert } from "node:assert";
import { describe, it } from "node:test";
import { calculatePartnerPayout } from "./calculatePartnerPayout.js";

describe("calculatePartnerPayout", () => {
  // -----------------------------------------------------------------------
  // AC2 + AC1: platform fee is deducted before applying partner share
  // -----------------------------------------------------------------------
  it("AC2: platform_fee_amount = transactionAmount * platformFeePercentage", () => {
    // With 100% partner share the payout should equal transactionAmount minus fee.
    const payout = calculatePartnerPayout(100, 0.05, 1.0);
    // fee = 100 * 0.05 = 5 → net = 95 → payout = 95 * 1.0 = 95.00
    assert.equal(payout, 95.0);
  });

  it("AC1: payout = (transactionAmount - platformFeeAmount) * partnerSharePercentage", () => {
    // fee = 200 * 0.10 = 20 → net = 180 → payout = 180 * 0.50 = 90.00
    const payout = calculatePartnerPayout(200, 0.10, 0.50);
    assert.equal(payout, 90.0);
  });

  // -----------------------------------------------------------------------
  // AC3: canonical example from the spec
  // -----------------------------------------------------------------------
  it("AC3: $100 transaction, 5% platform fee, 70% partner share → $66.50", () => {
    const payout = calculatePartnerPayout(100, 0.05, 0.70);
    assert.equal(payout, 66.50);
  });

  // -----------------------------------------------------------------------
  // AC4: fractional cents are floored, never rounded up
  // -----------------------------------------------------------------------
  it("AC4: fractional cents are floored (not rounded half-up)", () => {
    // fee = 0 * 0 = 0 → net = 10 → payout raw = 10 * (1/3) = 3.3333...
    // floor → 3.33
    const payout = calculatePartnerPayout(10, 0, 1 / 3);
    assert.equal(payout, 3.33);
  });

  it("AC4: value that would round up under half-up is still floored", () => {
    // 1/3 of $1 = $0.3333... → floor = $0.33, NOT $0.34
    const payout = calculatePartnerPayout(1, 0, 1 / 3);
    assert.equal(payout, 0.33);
  });

  it("AC4: value just below a whole cent is floored, not bumped up", () => {
    // 2/3 of $1 = $0.6666... → floor = $0.66, NOT $0.67
    const payout = calculatePartnerPayout(1, 0, 2 / 3);
    assert.equal(payout, 0.66);
  });

  it("AC4: exact cent values are unaffected by floor", () => {
    // 0.5 of $1 = $0.50 exactly → floor = $0.50
    const payout = calculatePartnerPayout(1, 0, 0.5);
    assert.equal(payout, 0.50);
  });

  // -----------------------------------------------------------------------
  // AC5: zero transaction amount yields zero payout
  // -----------------------------------------------------------------------
  it("AC5: transactionAmount = 0 → payout = 0", () => {
    const payout = calculatePartnerPayout(0, 0.05, 0.70);
    assert.equal(payout, 0);
  });

  it("AC5: zero transaction with zero fee and zero share → payout = 0", () => {
    const payout = calculatePartnerPayout(0, 0, 0);
    assert.equal(payout, 0);
  });

  // -----------------------------------------------------------------------
  // Additional precision / regression cases
  // -----------------------------------------------------------------------
  it("large transaction: $9999.99 at 3% fee, 80% share", () => {
    // fee = 9999.99 * 0.03 = 299.9997 → net = 9699.9903 → raw = 7759.99224
    // floor → 7759.99
    const payout = calculatePartnerPayout(9999.99, 0.03, 0.80);
    assert.equal(payout, 7759.99);
  });

  it("zero fee: payout = transactionAmount * partnerSharePercentage (floored)", () => {
    // fee = 0 → net = 50 → payout = 50 * 0.25 = 12.50
    const payout = calculatePartnerPayout(50, 0, 0.25);
    assert.equal(payout, 12.50);
  });

  it("zero partner share: payout = 0 regardless of transaction", () => {
    const payout = calculatePartnerPayout(1000, 0.05, 0);
    assert.equal(payout, 0);
  });
});

